using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API (JSONPlaceholder) via HttpClient.
/// Uses constructor injection — the SDK resolves DI services automatically.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Fetch a post by its numeric ID from the API.")]
    public async Task<string> GetPost(
        [Description("The post ID (1–100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var json = await httpClient.GetStringAsync($"/posts/{id}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("List posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter by user ID (omit for all posts)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Listing posts: {Url}", url);
        var json = await httpClient.GetStringAsync(url, cancellationToken);

        // Return a summary with count + first few items to avoid overwhelming the LLM
        using var doc = JsonDocument.Parse(json);
        var posts = doc.RootElement.EnumerateArray().Take(5).ToList();
        var total = doc.RootElement.GetArrayLength();

        var summary = new { total, showing = posts.Count, posts };
        return JsonSerializer.Serialize(summary, JsonOptions);
    }

    [McpServerTool, Description("Create a new post (simulated — the API echoes back the created resource).")]
    public async Task<string> CreatePost(
        [Description("Title of the post")] string title,
        [Description("Body content of the post")] string body,
        [Description("Author's user ID")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating post for user {UserId}", userId);
        var payload = new { title, body, userId };
        var response = await httpClient.PostAsJsonAsync("/posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

